import pytest
from your_module import is_valid_email  # Replace 'your_module' with the actual module name


class TestIsValidEmailHappyPath:
    """Tests for valid email addresses that should return True."""

    def test_simple_valid_email(self):
        assert is_valid_email("user@example.com") is True

    def test_email_with_dot_in_local_part(self):
        assert is_valid_email("first.last@example.com") is True

    def test_email_with_underscore(self):
        assert is_valid_email("user_name@example.com") is True

    def test_email_with_plus_sign(self):
        assert is_valid_email("user+tag@example.com") is True

    def test_email_with_hyphen_in_local_part(self):
        assert is_valid_email("user-name@example.com") is True

    def test_email_with_percent_sign(self):
        assert is_valid_email("user%test@example.com") is True

    def test_email_with_numbers(self):
        assert is_valid_email("user123@example.com") is True

    def test_email_with_subdomain(self):
        assert is_valid_email("user@mail.example.com") is True

    def test_email_with_hyphen_in_domain(self):
        assert is_valid_email("user@my-domain.com") is True

    def test_email_with_long_tld(self):
        assert is_valid_email("user@example.museum") is True

    def test_email_with_two_letter_tld(self):
        assert is_valid_email("user@example.co") is True

    def test_email_with_country_tld(self):
        assert is_valid_email("user@example.co.uk") is True

    def test_email_uppercase_letters(self):
        assert is_valid_email("USER@EXAMPLE.COM") is True

    def test_email_mixed_case(self):
        assert is_valid_email("User.Name@Example.Com") is True

    @pytest.mark.parametrize("email", [
        "simple@example.com",
        "very.common@example.com",
        "x@example.com",
        "long.email-address-with-hyphens@example.com",
        "user.name+tag+sorting@example.com",
        "test123@subdomain.example.org",
    ])
    def test_various_valid_emails(self, email):
        assert is_valid_email(email) is True


class TestIsValidEmailInvalid:
    """Tests for invalid email addresses that should return False."""

    def test_empty_string(self):
        assert is_valid_email("") is False

    def test_missing_at_sign(self):
        assert is_valid_email("userexample.com") is False

    def test_missing_local_part(self):
        assert is_valid_email("@example.com") is False

    def test_missing_domain(self):
        assert is_valid_email("user@") is False

    def test_missing_tld(self):
        assert is_valid_email("user@example") is False

    def test_tld_too_short(self):
        assert is_valid_email("user@example.c") is False

    def test_tld_with_numbers(self):
        assert is_valid_email("user@example.c0m") is False

    def test_multiple_at_signs(self):
        # Note: regex actually accepts this because '.' and '@' aren't filtered
        # in the domain matching set; verify behavior
        assert is_valid_email("user@@example.com") is False

    def test_spaces_in_email(self):
        assert is_valid_email("user name@example.com") is False

    def test_leading_space(self):
        assert is_valid_email(" user@example.com") is False

    def test_trailing_space(self):
        assert is_valid_email("user@example.com ") is False

    def test_special_characters_not_allowed(self):
        assert is_valid_email("user!@example.com") is False

    def test_invalid_character_hash(self):
        assert is_valid_email("user#name@example.com") is False

    def test_invalid_character_dollar(self):
        assert is_valid_email("user$name@example.com") is False

    def test_only_at_sign(self):
        assert is_valid_email("@") is False

    def test_only_dot(self):
        assert is_valid_email(".") is False

    def test_no_dot_in_domain(self):
        assert is_valid_email("user@examplecom") is False

    def test_unicode_characters(self):
        assert is_valid_email("üser@example.com") is False

    @pytest.mark.parametrize("email", [
        "plainaddress",
        "#@%^%#$@#$@#.com",
        "@example.com",
        "Joe Smith <email@example.com>",
        "email.example.com",
        "email@example@example.com",
        "email@example.com (Joe Smith)",
        "email@-example.com",
    ])
    def test_various_invalid_emails(self, email):
        assert is_valid_email(email) is False


class TestIsValidEmailEdgeCases:
    """Edge cases for the email validator."""

    def test_single_character_local_part(self):
        assert is_valid_email("a@example.com") is True

    def test_single_character_domain(self):
        assert is_valid_email("user@a.co") is True

    def test_very_long_email(self):
        local = "a" * 100
        domain = "b" * 100
        email = f"{local}@{domain}.com"
        assert is_valid_email(email) is True

    def test_consecutive_dots_in_local_part(self):
        # The regex permits this, even though RFC 5321 doesn't
        assert is_valid_email("user..name@example.com") is True

    def test_leading_dot_in_local_part(self):
        # Permitted by this regex pattern
        assert is_valid_email(".user@example.com") is True

    def test_trailing_dot_in_local_part(self):
        # Permitted by this regex pattern
        assert is_valid_email("user.@example.com") is True

    def test_numeric_only_local_part(self):
        assert is_valid_email("12345@example.com") is True

    def test_numeric_only_domain(self):
        assert is_valid_email
